import hashlib, os
def batch_hash(d, output='/tmp/hashes.csv'):
    entries=[]
    for name in sorted(os.listdir(d)):
        fp=os.path.join(d,name)
        if not os.path.isfile(fp): continue
        sha=hashlib.sha256()
        with open(fp,'rb') as f:
            for c in iter(lambda: f.read(8192), b''): sha.update(c)
        entries.append((name,sha.hexdigest()))
    with open(output,'w') as f:
        for n,h in entries: f.write(f'{n},{h}\n')
    print(f'Hashed {len(entries)} files -> {output}')
    for n,h in entries: print(f'  {n},{h[:12]}...')

import hashlib, re, os
def compare_versions(p1, p2):
    def info(fp):
        with open(fp,'rb') as f: data=f.read()
        h=hashlib.sha256(data).hexdigest()
        a=re.search(rb'/Author\s*\(([^)]+)\)',data)
        return len(data),h,a.group(1).decode() if a else None
    s1,h1,a1=info(p1); s2,h2,a2=info(p2)
    print('Version Comparison:')
    print(f'  Sizes: {s1}B vs {s2}B ({"same" if s1==s2 else "different"})')
    print(f'  Hashes: {"IDENTICAL" if h1==h2 else "DIFFERENT"}')
    if a1 and a2: print(f'  Same author: {"Yes" if a1==a2 else "No"} ({a1})')
    if h1!=h2 and a1==a2: print('  Likely: Different versions of same document')
    elif h1==h2: print('  Likely: Exact copies')

import os, re
def multi_timeline(d):
    events=[]
    for name in os.listdir(d):
        fp=os.path.join(d,name)
        with open(fp,'rb') as f: data=f.read()
        m=re.search(rb'/CreationDate\s*\(D:(\d{8})',data)
        if m:
            ds=m.group(1).decode()
            events.append((f'{ds[:4]}-{ds[4:6]}-{ds[6:8]}',name))
    events.sort()
    print('Document Timeline:')
    for date,name in events: print(f'  {date}  {name}')
